
// 用于单个拉取语言模型入参
export interface getI18nLanguageRequestPayload {
    /**
     * i18n api 地址，默认使用 https://i18n.spotterio.com
     */
    domainUrl?: string | null;
    /**
     * weblate 中的项目，用来区分线上线下环境
     * 线下环境: spotter-dev
     * 线上环境: spotter
      */
    project :string;
    /**
     * 偏好语言，默认使用 'zh'
     */
    language?: string | null;
    /**
     * 部件，用来定义需要获取哪些翻译文案的空间
      */
    component :string;
}
